import torch
import torch.nn as nn

def add_gradient_logging(model, log_every=100, step_counter=[0]):
    """
    Attach hooks to log gradient norms per layer every N steps.
    Useful for diagnosing vanishing/exploding gradients in training.
    """
    def make_hook(name):
        def hook(grad):
            step_counter[0] += 1
            if step_counter[0] % log_every == 0:
                norm = grad.norm().item()
                if norm < 1e-6:
                    print(f"  WARNING vanishing: {name} grad_norm={norm:.2e}")
                elif norm > 1e3:
                    print(f"  WARNING exploding: {name} grad_norm={norm:.2e}")
        return hook

    for name, param in model.named_parameters():
        if param.requires_grad:
            param.register_hook(make_hook(name))

# Training loop with gradient logging
class DeepModel(nn.Module):
    def __init__(self, depth=10):
        super().__init__()
        self.layers = nn.ModuleList([
            nn.Linear(64, 64) for _ in range(depth)
        ])
        self.act = nn.Sigmoid()  # deliberately bad activation

    def forward(self, x):
        for l in self.layers:
            x = self.act(l(x))
        return x.sum()

model = DeepModel(depth=10)
add_gradient_logging(model, log_every=1)

opt = torch.optim.SGD(model.parameters(), lr=0.01)
x   = torch.randn(8, 64)
for step in range(3):
    opt.zero_grad()
    loss = model(x)
    loss.backward()
    opt.step()
